```julia
using BenchmarkTools

function test_slow(n::Integer)
    s = "hello"
    buf = IOBuffer()
    for i in 1:n
        print(buf, s, i)
    end
end

function test_fast(n::Integer)
    s = "hello"
    buf = IOBuffer()
    for i in 1:n
        print(buf, s)
        print(buf, i)
    end
end

@btime test_slow(50_000);
@btime test_fast(50_000);
```

**Current nightly**

```julia
